@page "/book-appointment"
@using sv_b5b247d640814efd818696aa0ca882ea.Services
@inject AppointmentService AppointmentSvc
@rendermode InteractiveServer

<PageTitle>Book Appointment</PageTitle>

<h3 class="mb-4">Book an Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />

    @* ───── STEP 1 ───── *@
    <fieldset>
        <legend>Patient Information</legend>

        <div class="mb-3">
            <label class="form-label" for="patientName">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="email">Email</label>
            <InputText id="email" class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="phone">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label" for="insurance">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!ShowStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next
            </button>
        }
    </fieldset>

    @* ───── STEP 2 ───── *@
    @if (ShowStep2)
    {
        <fieldset class="mt-4">
            <legend>Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label" for="doctor">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select"
                             Value="Model.PreferredDoctor"
                             ValueChanged="(string v) => OnDoctorChanged(v)"
                             ValueExpression="() => Model.PreferredDoctor">
                    <option value="">-- Select --</option>
                    @foreach (var doc in Doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.PreferredDoctor" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="date">Date</label>
                <InputDate id="date" class="form-control"
                           Value="Model.AppointmentDate"
                           ValueChanged="(DateOnly? v) => OnDateChanged(v)"
                           ValueExpression="() => Model.AppointmentDate" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="timeSlot">Time Slot</label>
                <InputSelect id="timeSlot" class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in AvailableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label" for="reason">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" rows="3"
                               @bind-Value="Model.ReasonForVisit" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-outline-primary me-2" @onclick="CheckAvailability"
                    disabled="@IsChecking">
                @(IsChecking ? "Checking…" : "Check Availability")
            </button>

            @if (IsAvailable)
            {
                <button type="submit" class="btn btn-success">
                    Confirm Appointment
                </button>
            }
        </fieldset>
    }
</EditForm>

@if (IsSubmitted)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully for <strong>@Model.PatientName</strong>
        with <strong>@Model.PreferredDoctor</strong>
        on @Model.AppointmentDate?.ToString("MMMM d, yyyy") at @Model.TimeSlot.
    </div>
}

@code {
    private AppointmentModel Model { get; set; } = new();
    private EditContext editContext = default!;
    private ValidationMessageStore messageStore = default!;

    private bool ShowStep2;
    private bool IsChecking;
    private bool IsAvailable;
    private bool IsSubmitted;

    private List<string> Doctors = [];
    private List<string> AvailableSlots = [];

    protected override async Task OnInitializedAsync()
    {
        editContext = new EditContext(Model);
        messageStore = new ValidationMessageStore(editContext);
        editContext.OnFieldChanged += (_, args) =>
        {
            messageStore.Clear(args.FieldIdentifier);
            IsAvailable = false;
        };

        Doctors = await AppointmentSvc.GetDoctorsAsync();
    }

    private void ProceedToStep2()
    {
        messageStore.Clear();

        // Validate only step-1 fields
        var step1Valid =
            !string.IsNullOrWhiteSpace(Model.PatientName) &&
            !string.IsNullOrWhiteSpace(Model.Email) &&
            new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email) &&
            !string.IsNullOrWhiteSpace(Model.Phone) &&
            !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

        if (!step1Valid)
        {
            // Trigger DataAnnotations validation so messages appear
            editContext.Validate();
            return;
        }

        ShowStep2 = true;
    }

    private async Task OnDoctorChanged(string doctor)
    {
        Model.PreferredDoctor = doctor;
        Model.TimeSlot = "";
        IsAvailable = false;
        await LoadSlots();
    }

    private async Task OnDateChanged(DateOnly? date)
    {
        Model.AppointmentDate = date;
        Model.TimeSlot = "";
        IsAvailable = false;
        await LoadSlots();
    }

    private async Task LoadSlots()
    {
        if (!string.IsNullOrEmpty(Model.PreferredDoctor) && Model.AppointmentDate.HasValue)
        {
            AvailableSlots = await AppointmentSvc.GetAvailableSlotsAsync(
                Model.PreferredDoctor, Model.AppointmentDate.Value);
        }
        else
        {
            AvailableSlots = [];
        }
    }

    private async Task CheckAvailability()
    {
        messageStore.Clear();
        editContext.NotifyValidationStateChanged();

        // Run client-side validation first
        if (!editContext.Validate())
            return;

        IsChecking = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                Model.Email,
                Model.InsuranceProvider,
                Model.PreferredDoctor,
                Model.TimeSlot);

            if (errors.Count > 0)
            {
                foreach (var (field, message) in errors)
                {
                    messageStore.Add(editContext.Field(field), message);
                }
                editContext.NotifyValidationStateChanged();
                IsAvailable = false;
            }
            else
            {
                IsAvailable = true;
            }
        }
        finally
        {
            IsChecking = false;
        }
    }

    private void HandleSubmit()
    {
        if (IsAvailable)
        {
            IsSubmitted = true;
        }
    }
}

